import React, { useEffect, useRef } from 'react';

const VideoFrame = ({ src, onError }) => {
  const containerRef = useRef(null);

  useEffect(() => {
    if (src && containerRef.current) {
      // Crear iframe sin sandbox para evitar "Client blocked"
      const frame = document.createElement('iframe');

      // Solo atributos esenciales
      frame.src = src;
      frame.width = '100%';
      frame.height = '100%';
      frame.allowFullscreen = true;

      // Sin sandbox - solo bloqueo de clics
      frame.style.cssText = `
        border: none;
        background: #000;
        border-radius: 8px;
        width: 100%;
        height: 100%;
        pointer-events: none;
      `;

      // Limpiar y agregar
      containerRef.current.innerHTML = '';
      containerRef.current.appendChild(frame);

      frame.onload = () => {
        console.log('Iframe cargado sin sandbox');
      };

      // Verificar si carga
      const checkLoad = setTimeout(() => {
        try {
          if (!frame.contentWindow) {
            console.log('Iframe no cargó correctamente');
            if (onError) onError();
          }
        } catch (e) {
          console.log('Error verificando iframe:', e.message);
          if (onError) onError();
        }
      }, 5000);

      return () => {
        clearTimeout(checkLoad);
        if (containerRef.current) {
          containerRef.current.innerHTML = '';
        }
      };
    }
  }, [src, onError]);

  return (
    <div 
      ref={containerRef}
      className="w-full h-96 md:h-[500px] lg:h-[600px] bg-black rounded-lg relative overflow-hidden"
      style={{ 
        minHeight: '400px'
      }}
    >
      {/* Capa de protección anti-anuncios */}
      <div 
        className="absolute inset-0 z-10"
        style={{ pointerEvents: 'auto' }}
        onClick={(e) => {
          e.preventDefault();
          e.stopPropagation();
          console.log('Clic bloqueado - posible anuncio');
        }}
      >
        {/* Área del reproductor donde sí se permite clic */}
        <div 
          className="absolute top-1/2 left-1/2 transform -translate-x-1/2 -translate-y-1/2 w-20 h-20 bg-transparent rounded-full"
          style={{ pointerEvents: 'none' }}
          onClick={(e) => {
            e.stopPropagation();
            // Permitir clic en el reproductor
            const iframe = containerRef.current?.querySelector('iframe');
            if (iframe) {
              iframe.style.pointerEvents = 'auto';
              setTimeout(() => {
                iframe.style.pointerEvents = 'none';
              }, 1000);
            }
          }}
        >
          <div className="w-full h-full flex items-center justify-center text-white text-2xl opacity-50 hover:opacity-100">
            ▶️
          </div>
        </div>
      </div>

      {/* Botón de play manual */}
      <button
        className="absolute top-2 left-2 z-30 bg-green-600 hover:bg-green-700 text-white px-3 py-1 rounded text-sm font-bold"
        onClick={() => {
          const iframe = containerRef.current?.querySelector('iframe');
          if (iframe) {
            iframe.style.pointerEvents = 'auto';
            setTimeout(() => {
              iframe.style.pointerEvents = 'none';
            }, 2000);
          }
        }}
      >
        ▶️ PLAY
      </button>
    </div>
  );
};

export default VideoFrame;
